import React, { useState } from 'react';
import { X, Bot, Save, Check } from 'lucide-react';
import * as Icons from 'lucide-react';
import { BotFormData, ModelType } from '../types';
import { ICONS_LIST } from '../constants';

interface BotCreatorProps {
  onClose: () => void;
  onCreate: (data: BotFormData) => void;
}

const AVAILABLE_COLORS = [
  'bg-blue-500',
  'bg-red-500',
  'bg-green-500',
  'bg-yellow-500',
  'bg-purple-500',
  'bg-pink-500',
  'bg-indigo-500',
  'bg-teal-500',
  'bg-orange-500',
  'bg-cyan-500',
  'bg-slate-600',
  'bg-rose-500',
  'bg-emerald-600',
  'bg-violet-600',
];

export const BotCreator: React.FC<BotCreatorProps> = ({ onClose, onCreate }) => {
  const [formData, setFormData] = useState<BotFormData>({
    name: '',
    description: '',
    systemInstruction: '',
    model: ModelType.FLASH,
    avatarColor: AVAILABLE_COLORS[0],
    icon: ICONS_LIST[0]
  });

  const [errors, setErrors] = useState<{ name?: string; description?: string }>({});

  const validate = (): boolean => {
    const newErrors: { name?: string; description?: string } = {};

    if (!formData.name.trim()) {
      newErrors.name = 'El nombre es obligatorio.';
    } else if (formData.name.trim().length < 3) {
      newErrors.name = 'El nombre debe tener al menos 3 caracteres.';
    }

    if (!formData.description.trim()) {
      newErrors.description = 'La descripción es obligatoria.';
    } else if (formData.description.trim().length < 5) {
      newErrors.description = 'La descripción debe tener al menos 5 caracteres.';
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (validate()) {
      onCreate(formData);
    }
  };

  const renderIcon = (iconName: string, size = 20) => {
    const IconComponent = (Icons as any)[iconName] || Icons.Bot;
    return <IconComponent size={size} />;
  };

  return (
    <div className="fixed inset-0 bg-black/70 z-50 flex items-center justify-center p-4 backdrop-blur-sm">
      <div className="bg-slate-900 border border-slate-800 rounded-2xl w-full max-w-lg shadow-2xl flex flex-col max-h-[90vh]">

        <div className="p-5 border-b border-slate-800 flex justify-between items-center">
          <h2 className="text-xl font-bold text-white flex items-center gap-2">
            <Bot className="text-blue-500" /> Crear Nuevo Bot
          </h2>
          <button onClick={onClose} className="text-slate-400 hover:text-white">
            <X size={24} />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-5 overflow-y-auto custom-scrollbar">

          {/* Avatar Color Selector */}
          <div>
            <label className="block text-sm font-medium text-slate-300 mb-2">Color del Avatar</label>
            <div className="flex flex-wrap gap-2">
              {AVAILABLE_COLORS.map((color) => (
                <button
                  key={color}
                  type="button"
                  title={color.replace('bg-', '').replace(/-\d+/, '')}
                  onClick={() => setFormData({ ...formData, avatarColor: color })}
                  className={`w-8 h-8 rounded-full ${color} flex items-center justify-center transition-transform hover:scale-110 ring-offset-2 ring-offset-slate-900 ${
                    formData.avatarColor === color ? 'ring-2 ring-white scale-110' : ''
                  }`}
                >
                  {formData.avatarColor === color && <Check size={14} className="text-white drop-shadow-md" />}
                </button>
              ))}
            </div>
          </div>

          {/* Icon Selector */}
          <div>
            <label className="block text-sm font-medium text-slate-300 mb-2">Icono del Bot</label>
            <div className="flex flex-wrap gap-2">
              {ICONS_LIST.map((iconName) => (
                <button
                  key={iconName}
                  type="button"
                  onClick={() => setFormData({ ...formData, icon: iconName })}
                  className={`w-10 h-10 rounded-lg flex items-center justify-center transition-all border ${
                    formData.icon === iconName 
                    ? 'bg-blue-600 border-blue-400 text-white shadow-lg scale-105' 
                    : 'bg-slate-800 border-slate-700 text-slate-400 hover:bg-slate-700 hover:text-slate-200'
                  }`}
                  title={iconName}
                >
                  {renderIcon(iconName, 20)}
                </button>
              ))}
            </div>
          </div>

          {/* Title Input */}
          <div>
            <label className="block text-sm font-medium text-slate-300 mb-1">Título del Bot</label>
            <input 
              type="text" 
              className={`w-full bg-slate-950 border rounded-lg px-4 py-2 text-white focus:ring-2 outline-none transition-all ${
                errors.name 
                  ? 'border-red-500 focus:ring-red-500 focus:border-red-500' 
                  : 'border-slate-700 focus:ring-blue-600 focus:border-transparent'
              }`}
              placeholder="Ej: Profesor de Historia"
              value={formData.name}
              onChange={e => {
                setFormData({...formData, name: e.target.value});
                if (errors.name) setErrors({ ...errors, name: undefined });
              }}
            />
            {errors.name && (
              <p className="text-red-500 text-xs mt-1 flex items-center gap-1">
                <X size={12} /> {errors.name}
              </p>
            )}
          </div>

          {/* Description Input */}
          <div>
            <label className="block text-sm font-medium text-slate-300 mb-1">Descripción</label>
            <input 
              type="text" 
              className={`w-full bg-slate-950 border rounded-lg px-4 py-2 text-white focus:ring-2 outline-none transition-all ${
                errors.description
                  ? 'border-red-500 focus:ring-red-500 focus:border-red-500'
                  : 'border-slate-700 focus:ring-blue-600 focus:border-transparent'
              }`}
              placeholder="Ej: Experto en el Imperio Romano"
              value={formData.description}
              onChange={e => {
                setFormData({...formData, description: e.target.value});
                if (errors.description) setErrors({ ...errors, description: undefined });
              }}
            />
            {errors.description && (
              <p className="text-red-500 text-xs mt-1 flex items-center gap-1">
                <X size={12} /> {errors.description}
              </p>
            )}
          </div>

          <div>
            <label className="block text-sm font-medium text-slate-300 mb-1">Modelo Base</label>
            <select 
              className="w-full bg-slate-950 border border-slate-700 rounded-lg px-4 py-2 text-white focus:ring-2 focus:ring-blue-600 outline-none"
              value={formData.model}
              onChange={e => setFormData({...formData, model: e.target.value as ModelType})}
            >
              <option value={ModelType.FLASH_LITE}>Gemini Flash Lite (Baja Latencia / Ultra Rápido)</option>
              <option value={ModelType.FLASH}>Gemini 3 Flash (Equilibrado)</option>
              <option value={ModelType.PRO}>Gemini 3 Pro (Razonamiento Complejo)</option>
            </select>
          </div>

          <div>
            <label className="block text-sm font-medium text-slate-300 mb-1">
              Prompt del Sistema (Personalidad)
              <span className="text-slate-500 text-xs ml-2 block">Instrucciones detalladas sobre cómo debe comportarse el bot.</span>
            </label>
            <textarea 
              required
              className="w-full bg-slate-950 border border-slate-700 rounded-lg px-4 py-3 text-white focus:ring-2 focus:ring-blue-600 outline-none h-32 resize-none font-mono text-sm"
              placeholder="Ej: Eres un profesor de historia entusiasta. Usas analogías modernas para explicar eventos pasados..."
              value={formData.systemInstruction}
              onChange={e => setFormData({...formData, systemInstruction: e.target.value})}
            />
          </div>

          <div className="pt-2">
            <button 
              type="submit" 
              className="w-full bg-gradient-to-r from-blue-600 to-blue-500 hover:from-blue-500 hover:to-blue-400 text-white font-bold py-3 rounded-lg transition-all transform active:scale-[0.98] flex items-center justify-center gap-2 shadow-lg shadow-blue-900/20"
            >
              <Save size={20} /> Crear Bot
            </button>
          </div>

        </form>
      </div>
    </div>
  );
};

